# Use-case canvas submission handler: validate and route submitted use cases

from dataclasses import dataclass
from typing import Literal
import re

@dataclass
class UseCaseSubmission:
    champion_id: str
    business_unit: str
    process_name: str
    frequency: str          # "daily" | "weekly" | "monthly" | "ad_hoc"
    pain_points: str
    data_sources: list[str]
    ai_capability: str      # e.g. "text summarisation", "classification"
    success_metric: str
    estimated_time_saved_hrs_pw: float

    def is_complete(self) -> bool:
        required = [self.process_name, self.pain_points, self.success_metric]
        return all(bool(f and f.strip()) for f in required) and len(self.data_sources) > 0

    def risk_flag(self) -> str | None:
        """Flags high-sensitivity data sources for compliance review."""
        sensitive = {"customer pii", "financial records", "legal documents", "hr data"}
        lower = {d.lower() for d in self.data_sources}
        hits = sensitive & lower
        if hits:
            return f"Sensitive data sources detected: {', '.join(hits)}. Requires DPO review."
        return None

def route_submission(sub: UseCaseSubmission) -> dict:
    if not sub.is_complete():
        return {"status": "rejected", "reason": "Incomplete submission"}
    flag = sub.risk_flag()
    queue = "compliance_review" if flag else "feasibility_assessment"
    return {"status": "accepted", "queue": queue, "flag": flag}
